import glob
def strip_comment(s):
    out=[]; j=0
    while j<len(s):
        if s[j]=='\\' and j+1<len(s):
            out.append(s[j:j+2]); j+=2; continue
        if s[j]=='%':
            break
        out.append(s[j]); j+=1
    return ''.join(out)
def scan(path):
    issues=[]; in_dollar=False
    for ln,raw in enumerate(open(path),1):
        if raw.strip()=='':
            in_dollar=False  # paragraph break: math cannot span it
            continue
        s=strip_comment(raw)
        j=0
        while j<len(s):
            if s[j]=='\\' and j+1<len(s):
                pair=s[j:j+2]
                if pair=='\\(' and in_dollar: issues.append((ln,'open'))
                elif pair=='\\)' and in_dollar: issues.append((ln,'close'))
                j+=2; continue
            if s[j]=='$':
                in_dollar=not in_dollar
            j+=1
    return issues
grand=0
